import React from 'react'
import { Form as AntForm } from 'antd'

const { Item: AntFormItem } = AntForm

/**
 * Form ą║ąŠą╝ą┐ąŠąĮąĄąĮčé - ąŠą▒ąĄčĆčéą║ą░ ąĮą░ą┤ Ant Design Form
 */
export function Form({
  onFinish,
  initialValues,
  form,
  layout = 'vertical',
  ...rest
}) {
  return (
    <AntForm
      onFinish={onFinish}
      initialValues={initialValues}
      form={form}
      layout={layout}
      {...rest}
    />
  )
}

/**
 * FormItem ą║ąŠą╝ą┐ąŠąĮąĄąĮčé - ąŠą▒ąĄčĆčéą║ą░ ąĮą░ą┤ Ant Design Form.Item
 */
export function FormItem({
  label,
  name,
  rules,
  required,
  children,
  ...rest
}) {
  // ąĢčüą╗ąĖ required=true, ą┤ąŠą▒ą░ą▓ą╗čÅąĄą╝ ą║ rules
  const normalizedRules = rules || []
  if (required && !normalizedRules.some(r => r.required)) {
    normalizedRules.push({ required: true, message: `${label} ąŠą▒čÅąĘą░čéąĄą╗čīąĮąŠ ą┤ą╗čÅ ąĘą░ą┐ąŠą╗ąĮąĄąĮąĖčÅ` })
  }

  return (
    <AntFormItem
      label={label}
      name={name}
      rules={normalizedRules}
      {...rest}
    >
      {children}
    </AntFormItem>
  )
}

/**
 * ąĪąŠąĘą┤ą░ąĮąĖąĄ čŹą║ąĘąĄą╝ą┐ą╗čÅčĆą░ čäąŠčĆą╝čŗ
 */
export function useFormInstance() {
  return AntForm.useForm()
}
