let XAuthContext = createContext(null);

//ąĪą▓ąŠą╣čüčéą▓ąŠ publicMode čāą║ą░ąĘčŗą▓ą░čéčī ą┐čĆąŠą▓ą░ą╣ą┤ąĄčĆčā ą░čāčéąĄąĮčéąĖčäąĖą║ą░čåąĖąĖ, 
//čćčéąŠ ą┐čĆąĖ ąĮąĄą▓ąŠąĘą╝ąŠąČąĮąŠčüčéąĖ ąŠą▒ąĮąŠą▓ąĖčéčī čéąŠą║ąĄąĮ, ąĮąĄ ąĮčāąČąĮąŠ ą║ąĖą┤ą░čéčī ąĮą░ čüąĄčĆą▓ąĄčĆ ą░čāčéąĄąĮčéąĖčäąĖą║ą░čåąĖąĖ, 
//ą░ ąĮąĄąŠą▒čģąŠą┤ąĖą╝ąŠ čāą┤ą░ą╗ąĖčéčī ą║čāą║ąĖ čéąŠą║ąĄąĮą░ ąĖ čĆąĄčäčĆąĄčłąóąŠą║ąĄąĮą░, ąĖ ą┐ąĄčĆąĄąĘą░ą│čĆčāąĘąĖčéčī čéąĄą║čāčēčāčÄ čüčéčĆą░ąĮąĖčåčā.
export function AuthProvider({ children, publicMode, keepAlive }) {
    const auth = new AuthService();
    auth.setPublicMode(publicMode);

    auth.setKeepAlive(keepAlive);
    return <XAuthContext.Provider value={auth}>{children}</XAuthContext.Provider>;
}
export function useAuth() {
    let auth = useContext(XAuthContext);
    return auth;
}

export function RequireAuth({ children, inline }) {
    let auth = useAuth();
    auth.setPublicMode(true);

    if (!auth.loggedIn()) {
        // Redirect them to the /login page, but save the current location they were
        // trying to go to when they were redirected. This allows us to send them
        // along to that page after they login, which is a nicer user experience
        // than dropping them off on the home page.
        if (inline) {
            return inline;
        }
        if (typeof window !== 'undefined') {
            window.location.href = auth.authschemhttp + "://auth." + auth.getDomainWithoutSubdomain(window.location.href) + "/login?service=" + window.location.href;
        }
    }
    return <React.Fragment>{children}</React.Fragment>;
}
