import React from 'react'
import { Input as AntInput } from 'antd'

const { TextArea: AntTextArea } = AntInput

/**
 * Input ą║ąŠą╝ą┐ąŠąĮąĄąĮčé - ąŠą▒ąĄčĆčéą║ą░ ąĮą░ą┤ Ant Design Input
 *
 * ąØąŠčĆą╝ą░ą╗ąĖąĘčāąĄčé API ą┤ą╗čÅ ąĖčüą┐ąŠą╗čīąĘąŠą▓ą░ąĮąĖčÅ ą▓ fennec-core
 */
export function Input({ value, onChange, ...rest }) {
  // Ant Design Input ą┐ąĄčĆąĄą┤ą░ąĄčé event ą▓ onChange, ąĮą░ą╝ ąĮčāąČąĮąŠ čéąŠą╗čīą║ąŠ value
  const handleChange = (e) => {
    if (onChange) {
      onChange(e.target.value)
    }
  }

  return (
    <AntInput
      value={value}
      onChange={handleChange}
      {...rest}
    />
  )
}

/**
 * TextArea ą║ąŠą╝ą┐ąŠąĮąĄąĮčé - ąŠą▒ąĄčĆčéą║ą░ ąĮą░ą┤ Ant Design TextArea
 */
export function TextArea({ value, onChange, ...rest }) {
  const handleChange = (e) => {
    if (onChange) {
      onChange(e.target.value)
    }
  }

  return (
    <AntTextArea
      value={value}
      onChange={handleChange}
      {...rest}
    />
  )
}
