import _ from 'lodash'

/**
 * ąōąĄąĮąĄčĆą░čåąĖčÅ data-locator ą░čéčĆąĖą▒čāčéą░ ą┤ą╗čÅ čéąĄčüčéąĖčĆąŠą▓ą░ąĮąĖčÅ
 *
 * @param {string} locator - ąæą░ąĘąŠą▓čŗą╣ ą╗ąŠą║ą░čéąŠčĆ
 * @param {Object|string|number} obj - ą×ą▒čŖąĄą║čé čü ID/uuid/key ąĖą╗ąĖ ą┐čĆąĖą╝ąĖčéąĖą▓
 * @returns {string} ąŚąĮą░čćąĄąĮąĖąĄ ą┤ą╗čÅ data-locator
 *
 * @example
 * getLocator('button', { ID: 123 }); // 'buttonID123'
 * getLocator('item', { uuid: 'abc' }); // 'itemUUIDabc'
 * getLocator('button', 42); // 'button42'
 */
export function getLocator(locator, obj) {
  if (_.isObject(obj)) {
    let id = (obj?.ID) ? `ID${obj?.ID}` : ''
    let uuid = (obj?.uuid) ? `UUID${obj?.uuid}` : ''
    let key = (obj?.key) ? `KEY${obj?.key}` : ''
    let ID = id || uuid || key
    return (locator || '') + ID
  } else if (obj) {
    return (locator || '') + obj
  } else return (locator || '')
}

