/**
 * ąōąĄąĮąĄčĆąĖčĆčāąĄčé ąĘąĮą░čćąĄąĮąĖąĄ ą┤ą╗čÅ ą░čéčĆąĖą▒čāčéą░ data-locator čü ą┤ąŠą┐ąŠą╗ąĮąĖčéąĄą╗čīąĮčŗą╝ąĖ ą┐ą░čĆą░ą╝ąĄčéčĆą░ą╝ąĖ
 *
 * @param {string} id - ąŻąĮąĖą║ą░ą╗čīąĮčŗą╣ čćąĄą╗ąŠą▓ąĄą║ąŠčćąĖčéą░ąĄą╝čŗą╣ ąĖą┤ąĄąĮčéąĖčäąĖą║ą░čéąŠčĆ
 * @param {any} value - ąŚąĮą░čćąĄąĮąĖąĄ čŹą╗ąĄą╝ąĄąĮčéą░ (ąŠą┐čåąĖąŠąĮą░ą╗čīąĮąŠąĄ)
 * @param {Object} options - ąöąŠą┐ąŠą╗ąĮąĖčéąĄą╗čīąĮčŗąĄ ą┐ą░čĆą░ą╝ąĄčéčĆčŗ (ąŠą┐čåąĖąŠąĮą░ą╗čīąĮčŗąĄ)
 * @param {string} options.action - ąóąĖą┐ ą┤ąĄą╣čüčéą▓ąĖčÅ čü čŹą╗ąĄą╝ąĄąĮčéąŠą╝ (click, input, toggle ąĖ čé.ą┤.)
 * @param {string} options.type - ąóąĖą┐ čŹą╗ąĄą╝ąĄąĮčéą░ (button, input, checkbox, list-item ąĖ čé.ą┤.)
 * @param {number} options.index - ąśąĮą┤ąĄą║čü čŹą╗ąĄą╝ąĄąĮčéą░ ą▓ ą║ąŠą╗ą╗ąĄą║čåąĖąĖ
 * @returns {string} - ąŚąĮą░čćąĄąĮąĖąĄ ą┤ą╗čÅ ą░čéčĆąĖą▒čāčéą░ data-locator
 *
 * @example
 * getAILocator('submit-button', null, { type: 'button', action: 'click' });
 * // 'submit-button-type-button-action-click'
 *
 * getAILocator('user-item', 123, { type: 'list-item', index: 0 });
 * // 'user-item-value-123-type-list-item-index-0'
 */
export function getAILocator(id, value = null, options = {}) {
  if (!id || typeof id !== 'string') {
    console.warn('getLocator: id ą┤ąŠą╗ąČąĄąĮ ą▒čŗčéčī ąĮąĄą┐čāčüčéąŠą╣ čüčéčĆąŠą║ąŠą╣')
    return ''
  }

  // ą×čüąĮąŠą▓ąĮčŗąĄ ą║ąŠą╝ą┐ąŠąĮąĄąĮčéčŗ ą╗ąŠą║ą░čéąŠčĆą░
  const parts = [id]

  // ąöąŠą▒ą░ą▓ą╗čÅąĄą╝ čéąĖą┐ čŹą╗ąĄą╝ąĄąĮčéą░, ąĄčüą╗ąĖ čāą║ą░ąĘą░ąĮ
  if (options.type) {
    parts.push(`type-${options.type}`)
  }

  // ąöąŠą▒ą░ą▓ą╗čÅąĄą╝ ą┤ąĄą╣čüčéą▓ąĖąĄ, ąĄčüą╗ąĖ čāą║ą░ąĘą░ąĮąŠ
  if (options.action) {
    parts.push(`action-${options.action}`)
  }

  // ąöąŠą▒ą░ą▓ą╗čÅąĄą╝ ąĘąĮą░čćąĄąĮąĖąĄ, ąĄčüą╗ąĖ ą┐ąĄčĆąĄą┤ą░ąĮąŠ
  if (value !== null && value !== undefined) {
    const cleanValue = String(value).replace(/\s+/g, '-').toLowerCase()
    parts.push(`value-${cleanValue}`)
  }

  // ąöąŠą▒ą░ą▓ą╗čÅąĄą╝ ąĖąĮą┤ąĄą║čü, ąĄčüą╗ąĖ čāą║ą░ąĘą░ąĮ
  if (typeof options.index === 'number') {
    parts.push(`index-${options.index}`)
  }

  return parts.join('-')
}
