/**
 * Notifier API - ą░ą▒čüčéčĆą░ą║čåąĖčÅ ą┤ą╗čÅ čāą▓ąĄą┤ąŠą╝ą╗ąĄąĮąĖą╣ (ą▒ąĄąĘ ąĘą░ą▓ąĖčüąĖą╝ąŠčüčéąĖ ąŠčé UI-ą▒ąĖą▒ą╗ąĖąŠčéąĄą║ąĖ).
 * ą¤čĆąĖą╗ąŠąČąĄąĮąĖąĄ ąĖą╗ąĖ ą░ą┤ą░ą┐čéąĄčĆ ą╝ąŠąČąĄčé čāčüčéą░ąĮąŠą▓ąĖčéčī: setNotifier({ error: (msg) => message.error(msg) })
 */
let _notifier = null

export function setNotifier(notifier) {
  _notifier = notifier
}

export function getNotifier() {
  return _notifier
}

/**
 * ą×ą▒čĆą░ą▒ąŠčéčćąĖą║ ąŠčłąĖą▒ąŠą║ ą┐ąŠ čāą╝ąŠą╗čćą░ąĮąĖčÄ
 *
 * ąśčüą┐ąŠą╗čīąĘčāąĄčé notifier.error() ąĄčüą╗ąĖ čāčüčéą░ąĮąŠą▓ą╗ąĄąĮ (setNotifier), ąĖąĮą░čćąĄ console.error.
 * ąØąĄ ąĘą░ą▓ąĖčüąĖčé ąŠčé ą║ąŠąĮą║čĆąĄčéąĮąŠą╣ UI-ą▒ąĖą▒ą╗ąĖąŠčéąĄą║ąĖ.
 *
 * @param {Error} err - ą×ą▒čŖąĄą║čé ąŠčłąĖą▒ą║ąĖ
 * @param {Function} callback - ą×ą┐čåąĖąŠąĮą░ą╗čīąĮčŗą╣ callback ą┐ąŠčüą╗ąĄ ąŠą▒čĆą░ą▒ąŠčéą║ąĖ ąŠčłąĖą▒ą║ąĖ
 *
 * @example
 * fetch('/api/data')
 *   .then(processData)
 *   .catch(errorCatch)
 */
export const errorCatch = (err, callback) => {
  if (err) {
    const msg = '' + err
    if (_notifier?.error) {
      _notifier.error(msg)
    } else {
      console.error(msg)
    }
    if (callback) callback()
  }
}

/**
 * ą×ą▒čĆą░ą▒ąŠčéčćąĖą║ ąŠčłąĖą▒ąŠą║ čü alert (ą┤ą╗čÅ ą╝ąŠą▒ąĖą╗čīąĮčŗčģ)
 *
 * @param {Error} err - ą×ą▒čŖąĄą║čé ąŠčłąĖą▒ą║ąĖ
 * @param {Function} callback - ą×ą┐čåąĖąŠąĮą░ą╗čīąĮčŗą╣ callback
 */
export const errorAlert = (err, callback) => {
  const messageError = (err) => {
    const alertInstance = alert('ą×čłąĖą▒ą║ą░', err, [
      { text: 'OK', onPress: () => alertInstance?.close() }
    ])
    setTimeout(() => {
      alertInstance?.close()
    }, 5000)
  }
  if (err) {
    messageError('' + err)
    if (callback) callback()
  }
}

/**
 * ą¤ąŠą║ą░ąĘą░čéčī čüąŠąŠą▒čēąĄąĮąĖąĄ ąŠą▒ ąŠčłąĖą▒ą║ąĄ čćąĄčĆąĄąĘ alert
 *
 * @param {string} err - ąĪąŠąŠą▒čēąĄąĮąĖąĄ ąŠą▒ ąŠčłąĖą▒ą║ąĄ
 */
export const messageError = (err) => {
  const alertInstance = alert('ą×čłąĖą▒ą║ą░', err, [
    { text: 'OK', onPress: () => alertInstance?.close() }
  ])
  setTimeout(() => {
    alertInstance?.close()
  }, 5000)
}
