import React from 'react'
import { Select as AntSelect } from 'antd'

const { Option } = AntSelect

/**
 * Select ą║ąŠą╝ą┐ąŠąĮąĄąĮčé - ąŠą▒ąĄčĆčéą║ą░ ąĮą░ą┤ Ant Design Select
 *
 * ąØąŠčĆą╝ą░ą╗ąĖąĘčāąĄčé API ą┤ą╗čÅ ąĖčüą┐ąŠą╗čīąĘąŠą▓ą░ąĮąĖčÅ ą▓ fennec-core
 */
export function Select({
  value,
  onChange,
  options,
  multiple,
  searchable = true,
  loading,
  onSearch,
  ...rest
}) {
  // Ant Design ąĖčüą┐ąŠą╗čīąĘčāąĄčé mode="multiple" ą▓ą╝ąĄčüčéąŠ multiple prop
  const mode = multiple ? 'multiple' : undefined

  // Ant Design ąĖčüą┐ąŠą╗čīąĘčāąĄčé showSearch ą▓ą╝ąĄčüčéąŠ searchable
  const showSearch = searchable

  // Ant Design ąĖčüą┐ąŠą╗čīąĘčāąĄčé filterOption ą┐ąŠ čāą╝ąŠą╗čćą░ąĮąĖčÄ, ą╝čŗ ą╝ąŠąČąĄą╝ ąĄą│ąŠ ąĮą░čüčéčĆąŠąĖčéčī
  const filterOption = rest.filterOption !== undefined
    ? rest.filterOption
    : ((input, option) => {
      if (option?.children) {
        return option.children.toLowerCase().indexOf(input.toLowerCase()) >= 0
      }
      return false
    })

  return (
    <AntSelect
      value={value}
      onChange={onChange}
      mode={mode}
      showSearch={showSearch}
      loading={loading}
      onSearch={onSearch}
      filterOption={filterOption}
      optionFilterProp="children"
      {...rest}
    >
      {options?.map((opt) => (
        <Option key={opt.value} value={opt.value}>
          {opt.label}
        </Option>
      ))}
    </AntSelect>
  )
}
