import { FennecError } from '../error/FennecError'
import { errorCatch } from '../error/errorCatch'
import { QueryParams } from '../query'

/**
 * HTTP GET ąĘą░ą┐čĆąŠčü
 *
 * @param {Object} auth - ą×ą▒čŖąĄą║čé ą░čāčéąĄąĮčéąĖčäąĖą║ą░čåąĖąĖ
 * @param {string} url - URL ą┤ą╗čÅ ąĘą░ą┐čĆąŠčüą░
 * @param {Function} callback - Callback ą┐čĆąĖ čāčüą┐ąĄčģąĄ
 * @param {Function} error - Callback ą┐čĆąĖ ąŠčłąĖą▒ą║ąĄ
 */
export const GET = (auth, url, callback, error) => {
  auth.fetch(url)
    .then((res) => {
      if (res && res.status === true) {
        if (callback) {
          callback(res)
        }
      } else if (res && res.status === false) {
        throw new FennecError(res.message, '', res)
      }
    })
    .catch(error || errorCatch)
}

/**
 * HTTP GET ąĘą░ą┐čĆąŠčü čü query ą┐ą░čĆą░ą╝ąĄčéčĆą░ą╝ąĖ
 *
 * @param {Object} auth - ą×ą▒čŖąĄą║čé ą░čāčéąĄąĮčéąĖčäąĖą║ą░čåąĖąĖ
 * @param {string} url - URL ą┤ą╗čÅ ąĘą░ą┐čĆąŠčüą░
 * @param {Array|string} queryParams - Query ą┐ą░čĆą░ą╝ąĄčéčĆčŗ
 * @param {Function} callback - Callback ą┐čĆąĖ čāčüą┐ąĄčģąĄ
 * @param {Function} error - Callback ą┐čĆąĖ ąŠčłąĖą▒ą║ąĄ
 */
export const GETWITH = (auth, url, queryParams, callback, error) => {
  let ext = QueryParams(queryParams)
  GET(auth, url + (ext ? '?' + ext : ''), callback, error)
}

/**
 * HTTP POST ąĘą░ą┐čĆąŠčü
 *
 * @param {Object} auth - ą×ą▒čŖąĄą║čé ą░čāčéąĄąĮčéąĖčäąĖą║ą░čåąĖąĖ
 * @param {string} url - URL ą┤ą╗čÅ ąĘą░ą┐čĆąŠčüą░
 * @param {Object} object - ąöą░ąĮąĮčŗąĄ ą┤ą╗čÅ ąŠčéą┐čĆą░ą▓ą║ąĖ
 * @param {Function} callback - Callback ą┐čĆąĖ čāčüą┐ąĄčģąĄ
 * @param {Function} error - Callback ą┐čĆąĖ ąŠčłąĖą▒ą║ąĄ
 */
export const POST = (auth, url, object, callback, error) => {
  auth.fetch(url, {
    method: 'POST',
    body: JSON.stringify(object)
  })
    .then((res) => {
      if (res && res.status === true) {
        if (callback) {
          callback(res)
        }
      } else if (res && res.status === false) {
        throw new FennecError(res.message, '', res)
      }
    })
    .catch(error || errorCatch)
}

