// ==================== Promise-based API ====================

/**
 * HTTP GET ąĘą░ą┐čĆąŠčü (Promise)
 *
 * @param {Object} auth - ą×ą▒čŖąĄą║čé ą░čāčéąĄąĮčéąĖčäąĖą║ą░čåąĖąĖ
 * @param {string} url - URL ą┤ą╗čÅ ąĘą░ą┐čĆąŠčüą░
 * @returns {Promise} Promise čü čĆąĄąĘčāą╗čīčéą░čéąŠą╝
 */
export const GETP = (auth, url) => {
  return new Promise((resolve, reject) => {
    auth.fetch(url)
      .then((res) => {
        if (res && res.status === true) {
          resolve(res)
        } else if (res && res.status === false) {
          throw new FennecError(res.message, '', res)
        }
      })
      .catch(reject)
  })
}

