/**
 * Gets nested value from object by path
 * Supports array indexing and complex paths like "user.roles[0].name"
 * @param {Object} object - Source object
 * @param {string} subObject - Path to value (e.g., "user.role.name" or "items[0].title")
 * @returns {any} Value at path or undefined
 */
export function getObjectValue(object, subObject) {
  // ąĢčüą╗ąĖ ą┐čĆąĖčüčāčéčüčéą▓čāčÄčé ą┐ąŠą┤ ąŠą▒čŖąĄą║čéčŗ
  if (object && subObject) {
    // ąĀą░ąĘą▒ąĖą▓ą░ąĄą╝ čüčéčĆąŠą║čā subObject čćąĄčĆąĄąĘ "." ąĮąĄ čéčĆąŠą│ą░čÅ ą┐čĆąĖ čŹčéąŠą╝ čéąŠčćą║ąĖ ą▓ čāą│ą╗ąŠą▓čŗčģ čüą║ąŠą▒ą║ą░čģ [sdf.sdf]
    var subObjects = subObject
      .replace(/\[[\wą░-čÅąÉ-ą»čæąü\d\."']*\]/g, function (item) {
        return item.replace(".", "<<8>>")
      })
      .split(".")
      ?.map(function (item) {
        return item.replace(/<<8>>/g, ".")
      })

    // ą¤ąĄčĆąĄą▒ąĖčĆą░ąĄą╝ ą┐ąŠą┤ ąŠą▒čŖąĄą║čéčŗ
    for (var i = 0; i < subObjects.length; i++) {
      var index = subObjects[i].match(/\[.*\]/)
      var subObj = subObjects[i].replace(/\[.*\]/, "")

      if (subObj) {
        var lastObj = subObj

        if (object === null) {
          console.debug("ą×čłąĖą▒ą║ą░ ą┐ąŠą╗čāčćąĄąĮąĖčÅ ąŠą▒čŖąĄą║čéą░: " + subObject + "; ąØąĄ čāą┤ą░ąĄčéčüčÅ ąĮą░ą╣čéąĖ čüą▓ąŠą╣čüčéą▓ąŠ: " + "\"" + subObj + "\"")
          return
        }

        object = object[subObj]
        if (object === undefined) {
          console.debug("ą×čłąĖą▒ą║ą░ ą┐ąŠą╗čāčćąĄąĮąĖčÅ ąŠą▒čŖąĄą║čéą░: " + subObject + "; ąØąĄ čāą┤ą░ąĄčéčüčÅ ąĮą░ą╣čéąĖ čüą▓ąŠą╣čüčéą▓ąŠ: " + "\"" + subObj + "\"")
          return
        }

        // ą¤čĆąŠą▓ąĄčĆčÅąĄą╝ čÅą▓ą╗čÅąĄčéčüčÅ ą╗ąĖ ą┐ąŠą┤ ąŠą▒čŖąĄą║čé ą╝ą░čüčüąĖą▓ąŠą╝
        if (index) {
          var rexp = /\[([\wą░-čÅąÉ-ą»čæąü\d\.]+)\]|\[["|']([\wą░-čÅąÉ-ą»čæąü\d\.]+)["|']\]/g
          var matchArray

          // ą¤ąŠąĖčüą║ ą▓čüąĄčģ ąĖąĮą┤ąĄą║čüąŠą▓ ą┤ą╗čÅ n-ą╝ąĄčĆąĮąŠą│ąŠ ą╝ą░čüčüąĖą▓ą░
          while ((matchArray = rexp.exec(index))) {
            var matchIndex = matchArray[1] || matchArray[2]
            if (matchIndex) {
              object = object[matchIndex]
              if (object === undefined) {
                console.debug("ą×čłąĖą▒ą║ą░ ą┐ąŠą╗čāčćąĄąĮąĖčÅ ąŠą▒čŖąĄą║čéą░: " + subObject + "; ąØąĄ čüčāčēąĄčüčéą▓čāąĄčé čŹą╗ąĄą╝ąĄąĮčéą░ čü ąĖąĮą┤ąĄą║čüąŠą╝: \"" + matchIndex + "\" ą▓ ąŠą▒čŖąĄą║čéąĄ: " + lastObj)
                return
              }
            } else {
              console.debug("ą×čłąĖą▒ą║ą░ ą┐ąŠą╗čāčćąĄąĮąĖčÅ ąŠą▒čŖąĄą║čéą░: " + subObject + "; ąØąĄ ą╝ąŠą│čā ą┐ąŠą╗čāčćąĖčéčī čāą║ą░ąĘą░ąĮąĮčŗą╣ ąŠą▒čŖąĄą║čé. ą×čłąĖą▒ą║ą░ ą┐ąŠą╗čāčćąĄąĮąĖčÅ ąĖąĮą┤ąĄą║čüą░ čŹą╗ąĄą╝ąĄąĮčéą░.")
              return
            }
          }
        }
      } else {
        console.debug("ą×čłąĖą▒ą║ą░ ą┐ąŠą╗čāčćąĄąĮąĖčÅ ąŠą▒čŖąĄą║čéą░: " + subObject + "; ąØąĄ ą╝ąŠą│čā ą┐ąŠą╗čāčćąĖčéčī čāą║ą░ąĘą░ąĮąĮčŗą╣ ąŠą▒čŖąĄą║čé.")
        return
      }
    }
  }
  return object
}

/**
 * Gets nested value from object by path with default fallback
 * @param {Object} object - Source object
 * @param {string} subObject - Path to value
 * @param {any} defValue - Default value if path doesn't exist
 * @returns {any} Value at path or default value
 */
export function getObjectValueOrDefault(object, subObject, defValue) {
  var result = getObjectValue(object, subObject)
  if (result === undefined || result === null) {
    if (defValue !== undefined) {
      return defValue
    }
  }
  return result
}
