/**
 * READWITH - čćčéąĄąĮąĖąĄ čü query ą┐ą░čĆą░ą╝ąĄčéčĆą░ą╝ąĖ
 *
 * @param {Object} auth - ą×ą▒čŖąĄą║čé ą░čāčéąĄąĮčéąĖčäąĖą║ą░čåąĖąĖ
 * @param {string} name - ąØą░ąĘą▓ą░ąĮąĖąĄ ą╝ąŠą┤ąĄą╗ąĖ
 * @param {Array|string} queryParams - Query ą┐ą░čĆą░ą╝ąĄčéčĆčŗ
 * @param {Function} callback - Callback ą┐čĆąĖ čāčüą┐ąĄčģąĄ
 * @param {Function} error - Callback ą┐čĆąĖ ąŠčłąĖą▒ą║ąĄ
 *
 * @example
 * READWITH(auth, 'users', [QueryParam('age', 25), QueryOrder('name', 'asc')],
 *   (res) => console.log('Data:', res.data),
 *   (err) => console.error('Error:', err)
 * )
 */
export const READWITH = (auth, name, queryParams, callback, error) => {
  let ext = QueryParams(queryParams)
  GET(auth, '/api/query/' + name.toLowerCase() + (ext ? '?' + ext : ''), callback, error)
}

