import React, { createContext, useContext, useMemo } from 'react'

/**
 * UIContext - ą║ąŠąĮčéąĄą║čüčé ą┤ą╗čÅ UI ą░ą┤ą░ą┐čéąĄčĆą░
 *
 * ą¤čĆąĄą┤ąŠčüčéą░ą▓ą╗čÅąĄčé ą┤ąŠčüčéčāą┐ ą║ UI ą║ąŠą╝ą┐ąŠąĮąĄąĮčéą░ą╝ čćąĄčĆąĄąĘ Context API.
 * ą¤ąŠąĘą▓ąŠą╗čÅąĄčé ą║ąŠą╝ą┐ąŠąĮąĄąĮčéą░ą╝ fennec-core ą┐ąŠą╗čāčćą░čéčī UI ą║ąŠą╝ą┐ąŠąĮąĄąĮčéčŗ ąĖąĘ ą░ą┤ą░ą┐čéąĄčĆą░
 * ą▒ąĄąĘ ą┐čĆčÅą╝ąŠą╣ ąĘą░ą▓ąĖčüąĖą╝ąŠčüčéąĖ ąŠčé ą║ąŠąĮą║čĆąĄčéąĮąŠą╣ UI ą▒ąĖą▒ą╗ąĖąŠčéąĄą║ąĖ.
 */
const UIContext = createContext(null)

/**
 * UIProvider - ą┐čĆąŠą▓ą░ą╣ą┤ąĄčĆ UI ą░ą┤ą░ą┐čéąĄčĆą░
 *
 * ą×ą▒ąŠčĆą░čćąĖą▓ą░ąĄčé ą┐čĆąĖą╗ąŠąČąĄąĮąĖąĄ ąĖ ą┐čĆąĄą┤ąŠčüčéą░ą▓ą╗čÅąĄčé UI ą░ą┤ą░ą┐čéąĄčĆ ą▓čüąĄą╝ ą┤ąŠčćąĄčĆąĮąĖą╝ ą║ąŠą╝ą┐ąŠąĮąĄąĮčéą░ą╝.
 *
 * @param {Object} props
 * @param {UIAdapter} props.adapter - ąŁą║ąĘąĄą╝ą┐ą╗čÅčĆ UI ą░ą┤ą░ą┐čéąĄčĆą░ (AntdAdapter, MuiAdapter, etc.)
 * @param {React.ReactNode} props.children - ąöąŠčćąĄčĆąĮąĖąĄ ą║ąŠą╝ą┐ąŠąĮąĄąĮčéčŗ
 *
 * @example
 * import { UIProvider } from 'fennec-core';
 * import { AntdAdapter } from 'fennec-core/adapters/antd';
 *
 * function App() {
 *   return (
 *     <UIProvider adapter={new AntdAdapter()}>
 *       <YourApp />
 *     </UIProvider>
 *   );
 * }
 */
export function UIProvider({ children, adapter }) {
  // ą£ąĄą╝ąŠąĖąĘąĖčĆčāąĄą╝ ą░ą┤ą░ą┐čéąĄčĆ, čćčéąŠą▒čŗ ąĖąĘą▒ąĄąČą░čéčī ą╗ąĖčłąĮąĖčģ čĆąĄčĆąĄąĮą┤ąĄčĆąŠą▓
  const memoizedAdapter = useMemo(() => adapter, [adapter])

  return (
    <UIContext.Provider value={memoizedAdapter}>
      {children}
    </UIContext.Provider>
  )
}

/**
 * useUIAdapter - čģčāą║ ą┤ą╗čÅ ą┐ąŠą╗čāčćąĄąĮąĖčÅ UI ą░ą┤ą░ą┐čéąĄčĆą░
 *
 * ąÆąŠąĘą▓čĆą░čēą░ąĄčé čéąĄą║čāčēąĖą╣ UI ą░ą┤ą░ą┐čéąĄčĆ ąĖąĘ ą║ąŠąĮčéąĄą║čüčéą░.
 * ąĢčüą╗ąĖ ą░ą┤ą░ą┐čéąĄčĆ ąĮąĄ ąĮą░ą╣ą┤ąĄąĮ, ą▓čŗą▒čĆą░čüčŗą▓ą░ąĄčé ąŠčłąĖą▒ą║čā čü ą┐ąŠą┤čüą║ą░ąĘą║ąŠą╣.
 *
 * @returns {UIAdapter} ąŁą║ąĘąĄą╝ą┐ą╗čÅčĆ UI ą░ą┤ą░ą┐čéąĄčĆą░
 * @throws {Error} ąĢčüą╗ąĖ ąĖčüą┐ąŠą╗čīąĘčāąĄčéčüčÅ ą▓ąĮąĄ UIProvider
 *
 * @example
 * function MyComponent() {
 *   const ui = useUIAdapter();
 *   const Input = ui.Input;
 *   return <Input value={value} onChange={onChange} />;
 * }
 */
export function useUIAdapter() {
  const adapter = useContext(UIContext)

  if (!adapter) {
    throw new Error(
      'useUIAdapter must be used within UIProvider. ' +
      'Wrap your app with <UIProvider adapter={new AntdAdapter()}>'
    )
  }

  return adapter
}

/**
 * useUIOptional - ąŠą┐čåąĖąŠąĮą░ą╗čīąĮčŗą╣ čģčāą║ ą┤ą╗čÅ ą┐ąŠą╗čāčćąĄąĮąĖčÅ UI ą░ą┤ą░ą┐čéąĄčĆą░
 *
 * ąÆąŠąĘą▓čĆą░čēą░ąĄčé UI ą░ą┤ą░ą┐čéąĄčĆ ąĖą╗ąĖ null ąĄčüą╗ąĖ ą┐čĆąŠą▓ą░ą╣ą┤ąĄčĆ ąĮąĄ ąĮą░ą╣ą┤ąĄąĮ.
 * ą¤ąŠą╗ąĄąĘąĮąŠ ą┤ą╗čÅ ą║ąŠą╝ą┐ąŠąĮąĄąĮčéąŠą▓, ą║ąŠčéąŠčĆčŗąĄ ą╝ąŠą│čāčé čĆą░ą▒ąŠčéą░čéčī ą║ą░ą║ čü ą░ą┤ą░ą┐čéąĄčĆąŠą╝, čéą░ą║ ąĖ ą▒ąĄąĘ ąĮąĄą│ąŠ.
 *
 * @returns {UIAdapter|null} ąŁą║ąĘąĄą╝ą┐ą╗čÅčĆ UI ą░ą┤ą░ą┐čéąĄčĆą░ ąĖą╗ąĖ null
 *
 * @example
 * function MyComponent() {
 *   const ui = useUIOptional();
 *   if (!ui) {
 *     // Fallback ąĮą░ čüčéą░čĆčāčÄ čĆąĄą░ą╗ąĖąĘą░čåąĖčÄ
 *     return <OldImplementation />;
 *   }
 *   return <NewImplementation ui={ui} />;
 * }
 */
export function useUIOptional() {
  return useContext(UIContext)
}
